select specialty, engagement_tier, state, census_region, count(*) as prescriber_count, sum(total_claims) as total_claims, round(avg(total_drug_cost)::numeric, 2) as avg_drug_cost, round(avg(brand_prescribing_rate_pct)::numeric, 1) as avg_brand_rate, round(avg(avg_cost_per_claim)::numeric, 2) as avg_cost_per_claim, sum(opioid_claims) as opioid_claims, sum(antibiotic_claims) as antibiotic_claims, round(avg(avg_beneficiary_age)::numeric, 1) as avg_patient_age from public_marts.mart_prescriber_engagement group by specialty, engagement_tier, state, census_region
